+#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
+#[serde(rename_all = "snake_case")]
+pub enum PaneDragResizeNoopReason {
+    IdleWithoutActiveDrag,
+    ActiveDragAlreadyInProgress,
+    PointerMismatch,
+    TargetMismatch,
+    ActiveStateDisallowsDiscreteInput,
+    ThresholdNotReached,
+}
